type NewFloat32Case struct {
	name  string
	shape []int64
	data  []float32
}

func TestNewFloat32(t *testing.T) {
	cases := []NewFloat32Case{NewFloat32Case{name: "small tensor", shape: []int64{1, 3}, data: []float32{1.0, 2.0, 3.0}}}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			env, envErr := infer.Init()
			if envErr != nil {
				t.Skip(fmt.Sprintf("no inference backend: %v", envErr))
				return
			}
			defer infer.Cleanup(env)
			tensor, err := infer.NewFloat32(env, tc.shape, tc.data)
			assertNoError(t, err)
			assertEqual(t, infer.Dtype(tensor), "float32")
			got := infer.GetFloat32(tensor)
			assertEqual(t, len(got), len(tc.data))
			gotShape := infer.GetShape(tensor)
			assertEqual(t, len(gotShape), len(tc.shape))
			destroyErr := infer.Destroy(tensor)
			assertNoError(t, destroyErr)
		})
	}
}

